async (params, browser) => {
  // Open Figma file
  await browser.open(`${params.file_url}`)

  // Wait for editor to load
  await browser.waitForSelector('[class*="toolbar"], [data-testid="canvas"]', 20000)

  // Let editor initialize
  await browser.wait(3000)

  // Open comments panel
  await browser.click('[class*="comment"] button, [data-testid="comments-toggle"], [class*="toolbar_view"] [class*="comment"], button[aria-label*="Comment"], [class*="toolbar"] [class*="comment_icon"]')

  // Let comments panel load
  await browser.wait(2000)

  // Extract comments from panel
  const result = await browser.evaluate(`const comments = []; const threads = document.querySelectorAll('[class*="comment"][class*="thread"], .comment-thread, [class*="comment_thread"], [data-testid="comment-thread"]'); threads.forEach((thread, i) => { if (i >= 30) return; const messages = thread.querySelectorAll('[class*="comment_message"], [class*="comment_body"], [class*="message_content"]'); const authorEl = thread.querySelector('[class*="comment_author"], [class*="author_name"], [class*="user_name"]'); const timeEl = thread.querySelector('time, [class*="timestamp"], [class*="comment_date"]'); const resolvedEl = thread.querySelector('[class*="resolved"], [class*="resolve"]'); const isResolved = resolvedEl ? (resolvedEl.classList.toString().includes('resolved') || resolvedEl.getAttribute('aria-label')?.includes('resolved')) : false; const commentTexts = []; messages.forEach(msg => { commentTexts.push(msg.textContent.trim()); }); comments.push({ author: authorEl ? authorEl.textContent.trim() : '', content: commentTexts.length > 0 ? commentTexts.join(' | ') : thread.textContent.trim().substring(0, 300), timestamp: timeEl ? (timeEl.getAttribute('datetime') || timeEl.textContent.trim()) : '', resolved: isResolved }); }); return { file_url: window.location.href, comment_count: comments.length, comments: comments }`)

  return result
}
